"""Loan Service - Handles book checkout and check-in operations."""from datetime import datetimefrom ..models.loan import LoanRecordfrom ..config.constants import DEFAULT_LOAN_PERIOD_DAYS, REFERENCE_BOOK_LOAN_PERIOD_DAYSfrom .fine_service import FineCalculatorclass LoanService:    """    Manages book lending operations with proper validation.    Follows the Pseudo-code Programming Process (PPP).    """    def __init__(self, book_collection, member_collection, loan_collection, fine_calculator=None):        self.books = book_collection        self.members = member_collection        self.loans = loan_collection        self.fine_calculator = fine_calculator or FineCalculator()    def check_out_book(self, member_id, isbn, checkout_date=None):        """        Check out a book to a member.        Returns:            tuple: (success: bool, message: str, loan: LoanRecord or None)        """        # 1. Validate book        book = self.books.find_by_isbn(isbn)        if not book:            return False, f"Book with ISBN '{isbn}' not found", None        if not book.is_available():            return False, f"'{book.title}' is already checked out", None        # 2. Validate member        member = self.members.find_by_id(member_id)        if not member:            return False, f"Member with ID '{member_id}' not found", None        can_borrow, reason = member.can_borrow()        if not can_borrow:            return False, reason, None        # 3. Determine loan period        if book.is_reference:            loan_period = REFERENCE_BOOK_LOAN_PERIOD_DAYS        else:            loan_period = DEFAULT_LOAN_PERIOD_DAYS        # 4. Create loan        loan = LoanRecord.create_loan(            book_isbn=isbn,            member_id=member_id,            checkout_date=checkout_date,            loan_period_days=loan_period        )        # 5. Update state        book.check_out()        member.borrow_book(isbn)        self.loans.add_loan(loan)        return True, f"'{book.title}' checked out. Due: {loan.due_date.strftime('%Y-%m-%d')}", loan    def check_in_book(self, isbn, member_id=None, return_date=None):        """        Check in a returned book. Optionally verify the returning member.        Args:            isbn (str): ISBN of the book being returned            member_id (str, optional): ID of the member returning the book            return_date (datetime, optional): Date of return        Returns:            tuple: (success: bool, message: str, fine_amount: float or None)        """        # 1. Find active loan        active_loan = self.loans.get_active_loan_for_book(isbn)        if not active_loan:            return False, f"No active loan found for book '{isbn}'", None        # 2. If member_id provided, verify it matches the loan        if member_id is not None and active_loan.member_id != member_id:            return False, f"This book was not borrowed by member '{member_id}'", None        # 3. Get associated objects        book = self.books.find_by_isbn(isbn)        member = self.members.find_by_id(active_loan.member_id)        if not book or not member:            return False, "Internal error: Book or member not found", None        return_dt = return_date or datetime.now()        # 4. Calculate fine if overdue        fine_amount = 0.0        if active_loan.is_overdue(return_dt):            fine_amount = self.fine_calculator.calculate_loan_fine(active_loan, return_dt)            member.add_fine(fine_amount)        # 5. Update records        active_loan.mark_returned(return_dt)        self.loans.close_loan(isbn)  # <-- ADD THIS LINE        book.check_in()        member.return_book(isbn)        # 6. Message        if fine_amount > 0:            message = f"Book returned. Fine: ${fine_amount:.2f}"        else:            message = "Book returned. No fine."        return True, message, fine_amount